    }
    
    enum LogLevel: String {
        case debug = "DEBUG"
        case info = "INFO"
        case warning = "WARNING"
        case error = "ERROR"
        case critical = "CRITICAL"
    }
    
    enum LogCategory: String {
        case authentication = "AUTH"
        case apiCall = "API"
        case userDataChange = "USER_DATA"
        case navigation = "NAVIGATION"
        case userInteraction = "INTERACTION"
        case errorCondition = "ERROR"
        case performance = "PERFORMANCE"
        case lifecycle = "LIFECYCLE"
        case network = "NETWORK"
        case storage = "STORAGE"
    }
    
    // MARK: - Session Tracking
    
    private func setupSessionTracking() {
        NotificationCenter.default.addObserver(self, selector: #selector(appDidBecomeActive), name: UIApplication.didBecomeActiveNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(appDidEnterBackground), name: UIApplication.didEnterBackgroundNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(appWillTerminate), name: UIApplication.willTerminateNotification, object: nil)
        
        log(level: .info, category: .lifecycle, message: "Analytics Logger initialized", metadata: ["sessionId": sessionId])
    }
    
    @objc private func appDidBecomeActive() {
        log(level: .info, category: .lifecycle, message: "App became active", metadata: [
            "sessionId": sessionId,
            "userId": userId ?? "none",
            "userEmail": userEmail ?? "none"
        ])
    }
    
    @objc private func appDidEnterBackground() {
        log(level: .info, category: .lifecycle, message: "App entered background", metadata: [
            "sessionId": sessionId,
            "bufferedLogs": "\(logBuffer.count)"
        ])
        flushLogs()
    }
    
    @objc private func appWillTerminate() {
        log(level: .info, category: .lifecycle, message: "App will terminate", metadata: [
            "sessionId": sessionId,
            "userId": userId ?? "none"
        ])
        flushLogs()
    }
    
    // MARK: - Core Logging
    
    func log(level: LogLevel, category: LogCategory, message: String, metadata: [String: String]? = nil, file: String = #file, function: String = #function, line: Int = #line) {
        let timestamp = dateFormatter.string(from: Date())
        let fileName = (file as NSString).lastPathComponent
        
        let entry = LogEntry(
            timestamp: timestamp,
            level: level.rawValue,
            category: category.rawValue,
            message: message,
            metadata: metadata,
            sessionId: sessionId,
            userId: userId,
            userEmail: userEmail
        )
        
        let metadataString = metadata?.map { "\($0.key)=\($0.value)" }.joined(separator: ", ") ?? ""
        let fullMessage = "[\(timestamp)] [\(level.rawValue)] [\(category.rawValue)] [\(fileName):\(line) \(function)] \(message) | User: \(userId ?? "N/A") | Email: \(userEmail ?? "N/A") | Session: \(sessionId) | Metadata: {\(metadataString)}"
        
        // Log via NSLog for crash report capture
        NSLog("%@", fullMessage)
        
        // Also print for Xcode console with color indicators
        let emoji: String
        switch level {
        case .debug: emoji = "🔍"
        case .info: emoji = "ℹ️"
        case .warning: emoji = "⚠️"
        case .error: emoji = "❌"
        case .critical: emoji = "🔥"
        }
        print("\(emoji) \(fullMessage)")
        
        // Buffer the entry
        logQueue.async { [weak self] in
            self?.bufferEntry(entry)
        }
    }
    
    private func bufferEntry(_ entry: LogEntry) {
        logBuffer.append(entry)
        if logBuffer.count >= maxBufferSize {
            flushLogs()
        }
    }
    
    private func flushLogs() {
        logQueue.async { [weak self] in
            guard let self = self, !self.logBuffer.isEmpty else { return }
            self.writeLogsToFile(self.logBuffer)
            self.logBuffer.removeAll()
        }
    }
    
    private func writeLogsToFile(_ entries: [LogEntry]) {
        guard let fileURL = logFileURL else { return }
        
        do {
            let encoder = JSONEncoder()
            encoder.outputFormatting = .prettyPrinted
            let data = try encoder.encode(entries)
            
            if FileManager.default.fileExists(atPath: fileURL.path) {
                let fileHandle = try FileHandle(forWritingTo: fileURL)
                fileHandle.seekToEndOfFile()
                fileHandle.write(data)
                fileHandle.write("\n".data(using: .utf8)!)
                fileHandle.closeFile()
            } else {
                try data.write(to: fileURL, options: .atomicWrite)
            }
        } catch {
            NSLog("Failed to write logs to file: %@", error.localizedDescription)
        }
    }
    
